func activityLabel(kind string) string {
	switch kind {
	case "comment":
		return "💬 comment posted"
	case "attachment":
		return "📎 file added"
	case "todo":
		return "✓ todo added"
	case "project":
		return "✎ project edited"
	}
	return kind
}

// humanBytes formats a byte count in IEC units. Inlined to avoid a
// new util package and to keep the template self-contained.
func humanBytes(n int64) string {
	const k = 1024
	if n < k {
		return strconv.FormatInt(n, 10) + " B"
	}
	units := []string{"K", "M", "G", "T"}
	v := float64(n) / float64(k)
	i := 0
	for v >= float64(k) && i < len(units)-1 {
		v /= float64(k)
		i++
	}
	if v < 10 {
		return strconv.FormatFloat(v, 'f', 1, 64) + " " + units[i] + "B"
	}
	return strconv.FormatInt(int64(v), 10) + " " + units[i] + "B"
}

// jsQuoteAttr escapes a string for inclusion inside a single-quoted
// JSON value rendered into a data-signals attribute. Only the four
// chars that break the literal need escaping.
func jsQuoteAttr(s string) string {
	out := make([]rune, 0, len(s))
	for _, r := range s {
		switch r {
		case '\\', '\'':
			out = append(out, '\\', r)
		case '\n':
			out = append(out, '\\', 'n')
		case '\r':
			out = append(out, '\\', 'r')
		default:
			out = append(out, r)
		}
	}
	return string(out)
}

